+const NO_ACTIVE_SNAPSHOT_MARKER_MS: u64 = u64::MAX;
+
+#[derive(Debug)]
+struct ConnectionPoolLiveMetrics {
+    connection_id: u64,
+    opened_at_ms: u64,
+    last_activity_ms: AtomicU64,
+    queries_executed: AtomicU64,
+    prepare_calls: AtomicU64,
+    transactions_started: AtomicU64,
+    open_transactions: AtomicU64,
+    active_snapshot_started_ms: AtomicU64,
+}
+
+impl ConnectionPoolLiveMetrics {
+    fn new(connection_id: u64, opened_at_ms: u64) -> Self {
+        Self {
+            connection_id,
+            opened_at_ms,
+            last_activity_ms: AtomicU64::new(opened_at_ms),
+            queries_executed: AtomicU64::new(0),
+            prepare_calls: AtomicU64::new(0),
+            transactions_started: AtomicU64::new(0),
+            open_transactions: AtomicU64::new(0),
+            active_snapshot_started_ms: AtomicU64::new(NO_ACTIVE_SNAPSHOT_MARKER_MS),
+        }
+    }
+
+    fn note_activity(&self, now_ms: u64) {
+        self.last_activity_ms.store(now_ms, AtomicOrdering::Relaxed);
+    }
+
+    fn note_prepare(&self, now_ms: u64) {
+        self.prepare_calls.fetch_add(1, AtomicOrdering::Relaxed);
+        self.note_activity(now_ms);
+    }
+
+    fn note_statement_execution_count(&self, count: usize, now_ms: u64) {
+        if count == 0 {
+            return;
+        }
+        self.queries_executed.fetch_add(
+            u64::try_from(count).unwrap_or(u64::MAX),
+            AtomicOrdering::Relaxed,
+        );
+        self.note_activity(now_ms);
+    }
+
+    fn note_transaction_started(&self, now_ms: u64) {
+        self.transactions_started
+            .fetch_add(1, AtomicOrdering::Relaxed);
+        self.open_transactions.store(1, AtomicOrdering::Relaxed);
+        self.active_snapshot_started_ms
+            .store(now_ms, AtomicOrdering::Relaxed);
+        self.note_activity(now_ms);
+    }
+
+    fn note_transaction_finished(&self, now_ms: u64) {
+        self.open_transactions.store(0, AtomicOrdering::Relaxed);
+        self.active_snapshot_started_ms
+            .store(NO_ACTIVE_SNAPSHOT_MARKER_MS, AtomicOrdering::Relaxed);
+        self.note_activity(now_ms);
+    }
+
+    fn snapshot(&self, now_ms: u64) -> ConnectionPoolEntrySnapshot {
+        let open_transactions_raw = self.open_transactions.load(AtomicOrdering::Relaxed);
+        let open_transactions = u32::try_from(open_transactions_raw).unwrap_or(u32::MAX);
+        let active_snapshot_started_ms = self
+            .active_snapshot_started_ms
+            .load(AtomicOrdering::Relaxed);
+        let active_snapshot_age_ms = (active_snapshot_started_ms != NO_ACTIVE_SNAPSHOT_MARKER_MS)
+            .then(|| now_ms.saturating_sub(active_snapshot_started_ms));
+
+        ConnectionPoolEntrySnapshot {
+            lifecycle: ConnectionLifecycleSnapshot {
+                connection_id: self.connection_id,
+                age_ms: now_ms.saturating_sub(self.opened_at_ms),
+                idle_ms: now_ms.saturating_sub(self.last_activity_ms.load(AtomicOrdering::Relaxed)),
+                open_transactions,
+                active_snapshot_age_ms,
+                queries_executed: self.queries_executed.load(AtomicOrdering::Relaxed),
+                prepare_calls: self.prepare_calls.load(AtomicOrdering::Relaxed),
+            },
+            transactions_started: self.transactions_started.load(AtomicOrdering::Relaxed),
+        }
+    }
+}
+
+#[derive(Debug, Clone)]
+struct ConnectionPoolEntrySnapshot {
+    lifecycle: ConnectionLifecycleSnapshot,
+    transactions_started: u64,
+}
+
+#[derive(Debug, Clone)]
+struct ConnectionPoolRegistrySnapshot {
+    open_connections: usize,
+    idle_connections: usize,
+    active_transactions: usize,
+    connection_age_max_ms: u64,
+    idle_ms_max: u64,
+    queries_executed_total: u64,
+    prepare_calls_total: u64,
+    transactions_started_total: u64,
+    connect_events_total: u64,
+    disconnect_events_total: u64,
+    connections: Vec<ConnectionPoolEntrySnapshot>,
+}
+
+#[derive(Debug)]
+struct SharedConnectionPoolRegistry {
+    epoch: Instant,
+    next_connection_id: AtomicU64,
+    connect_events_total: AtomicU64,
+    disconnect_events_total: AtomicU64,
+    connections: Mutex<HashMap<u64, Arc<ConnectionPoolLiveMetrics>>>,
+}
+
+impl SharedConnectionPoolRegistry {
+    fn new() -> Self {
+        Self {
+            epoch: Instant::now(),
+            next_connection_id: AtomicU64::new(1),
+            connect_events_total: AtomicU64::new(0),
+            disconnect_events_total: AtomicU64::new(0),
+            connections: Mutex::new(HashMap::new()),
+        }
+    }
+
+    fn now_ms(&self) -> u64 {
+        u64::try_from(self.epoch.elapsed().as_millis()).unwrap_or(u64::MAX)
+    }
+
+    fn register_connection(&self) -> Arc<ConnectionPoolLiveMetrics> {
+        let opened_at_ms = self.now_ms();
+        let connection_id = self
+            .next_connection_id
+            .fetch_add(1, AtomicOrdering::Relaxed);
+        let metrics = Arc::new(ConnectionPoolLiveMetrics::new(connection_id, opened_at_ms));
+        lock_unpoisoned(&self.connections).insert(connection_id, Arc::clone(&metrics));
+        self.connect_events_total
+            .fetch_add(1, AtomicOrdering::Relaxed);
+        metrics
+    }
+
+    fn release_connection(&self, connection_id: u64) {
+        let removed = lock_unpoisoned(&self.connections).remove(&connection_id);
+        if removed.is_some() {
+            self.disconnect_events_total
+                .fetch_add(1, AtomicOrdering::Relaxed);
+        }
+    }
+
+    fn snapshot(&self) -> ConnectionPoolRegistrySnapshot {
+        let now_ms = self.now_ms();
+        let connections = {
+            let tracked = lock_unpoisoned(&self.connections);
+            tracked.values().cloned().collect::<Vec<_>>()
+        };
+        let connection_snapshots = connections
+            .iter()
+            .map(|metrics| metrics.snapshot(now_ms))
+            .collect::<Vec<_>>();
+        let idle_connections = connection_snapshots
+            .iter()
+            .filter(|entry| entry.lifecycle.open_transactions == 0)
+            .count();
+        let active_transactions = connection_snapshots
+            .iter()
+            .filter(|entry| entry.lifecycle.open_transactions > 0)
+            .count();
+        let connection_age_max_ms = connection_snapshots
+            .iter()
+            .map(|entry| entry.lifecycle.age_ms)
+            .max()
+            .unwrap_or(0);
+        let idle_ms_max = connection_snapshots
+            .iter()
+            .map(|entry| entry.lifecycle.idle_ms)
+            .max()
+            .unwrap_or(0);
+        let queries_executed_total = connection_snapshots
+            .iter()
+            .map(|entry| entry.lifecycle.queries_executed)
+            .sum();
+        let prepare_calls_total = connection_snapshots
+            .iter()
+            .map(|entry| entry.lifecycle.prepare_calls)
+            .sum();
+        let transactions_started_total = connection_snapshots
+            .iter()
+            .map(|entry| entry.transactions_started)
+            .sum();
+
+        ConnectionPoolRegistrySnapshot {
+            open_connections: connection_snapshots.len(),
+            idle_connections,
+            active_transactions,
+            connection_age_max_ms,
+            idle_ms_max,
+            queries_executed_total,
+            prepare_calls_total,
+            transactions_started_total,
+            connect_events_total: self.connect_events_total.load(AtomicOrdering::Relaxed),
+            disconnect_events_total: self.disconnect_events_total.load(AtomicOrdering::Relaxed),
+            connections: connection_snapshots,
+        }
+    }
+}
